/**
 * Comprehensive compound library for type-ahead search.
 * When a user selects a compound, the form auto-populates with standard defaults.
 * Users verify and adjust before saving.
 */

export interface LibraryEntry {
  name: string;
  category: string;
  unitSize: number;       // mg per vial/container or count per bottle
  unitLabel: string;
  unitPrice: number;      // typical price
  kitPrice: number | null;
  dosePerUse: number;
  doseLabel: string;
  bacstatPerVial: number | null;  // IU per reconstituted vial (peptides)
  reconVolume: number | null;     // mL bacstat water
  dosesPerDay: number;
  daysPerWeek: number;
  timingNote: string;
  cycleOnDays: number | null;
  cycleOffDays: number | null;
  vialSizeMl: number | null;
  aliases?: string[];     // alternative names for search matching
}

