/**
 * Search the library with fuzzy matching against name and aliases.
 */
export function searchCompoundLibrary(query: string, limit = 20): LibraryEntry[] {
  if (!query || query.length < 1) return [];
  const q = query.toLowerCase().trim();
  
  // Score each entry
  const scored = COMPOUND_LIBRARY.map(entry => {
    const name = entry.name.toLowerCase();
    const aliases = (entry.aliases || []).map(a => a.toLowerCase());
    
    let score = 0;
    // Exact name match
    if (name === q) score = 100;
    // Name starts with query
    else if (name.startsWith(q)) score = 80;
    // Alias exact match
    else if (aliases.some(a => a === q)) score = 75;
    // Alias starts with query
    else if (aliases.some(a => a.startsWith(q))) score = 70;
    // Name contains query
    else if (name.includes(q)) score = 60;
    // Alias contains query
    else if (aliases.some(a => a.includes(q))) score = 50;
    // Category match
    else if (entry.category.toLowerCase().includes(q)) score = 30;
    // Word-level match (any word in name starts with q)
    else if (name.split(/[\s\-()]+/).some(w => w.startsWith(q))) score = 55;
    
    return { entry, score };
  })
  .filter(s => s.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, limit);
  
  return scored.map(s => s.entry);
}
